typedef unsigned u32;
extern __declspec(dllimport) void cont(void);
extern __declspec(dllimport) void *pop(u32 size);
extern __declspec(dllimport) void push(const void *p, u32 size);
/* stack: y origin_y row_h count  (f32,f32,f32,u32) -> i32 index or -1 */
__declspec(dllexport) void run(void) {
    u32 count = *(u32*)pop(4);
    float row_h = *(float*)pop(4);
    float origin_y = *(float*)pop(4);
    float y = *(float*)pop(4);
    int idx = -1;
    if (row_h > 0.0f && count > 0) {
        float rel = y - origin_y;
        if (rel >= 0.0f) {
            int i = (int)(rel / row_h);
            if (i >= 0 && (u32)i < count) idx = i;
        }
    }
    push(&idx, 4);
    cont();
}


==== mods_src/point_in_rect.c ====
typedef unsigned u32;
extern __declspec(dllimport) void cont(void);
extern __declspec(dllimport) void *pop(u32 size);
extern __declspec(dllimport) void push(const void *p, u32 size);
/* stack: x y rx ry rw rh  (all f32) -> u32 0/1
 * hit if x in [rx,rx+rw) and y in [ry,ry+rh)
 */
__declspec(dllexport) void run(void) {
    float rh = *(float*)pop(4);
    float rw = *(float*)pop(4);
    float ry = *(float*)pop(4);
    float rx = *(float*)pop(4);
    float y  = *(float*)pop(4);
    float x  = *(float*)pop(4);
    u32 v = (x >= rx && x < rx + rw && y >= ry && y < ry + rh) ? 1u : 0u;
    push(&v, 4);
    cont();
}


