/* payload layout: f32 x, f32 y, f32 w, f32 h, u32 ARGB, f32 stroke, u32 fill */
__declspec(dllexport) void run(void) {
    u8 *p = cvm_payload();
    u32 n = cvm_payload_size();
    if (n >= 28) {
        float x = *(float*)(p + 0);
        float y = *(float*)(p + 4);
        float w = *(float*)(p + 8);
        float h = *(float*)(p + 12);
