    H oldh;
    u32 n = cvm_payload_size();
    u8 *p = cvm_payload();

    if (n >= 32) memcpy(k, p, 32);
    cvm_resolve_payload_hash(k, oldh);
    if (!cvm_hash_same(oldh, k) && n >= 32) {
        memcpy(p, oldh, 32);
